import{a as e,c as t,i as n,l as r,n as i,o as a,r as o,s,t as c}from"./app-F1EwwXV_.js";import"./my-photo-DNrNUHKE.js";var l=JSON.parse(`{"path":"/zh-tw/about.html","title":"關於我","lang":"zh-TW","frontmatter":{"title":"關於我","contributors":false},"git":{"updatedTime":1774698727000,"changelog":[{"hash":"cff23f05e912c819f2d68ca2eae71192c73adc8e","time":1774698727000,"email":"roufangwang@gmail.com","author":"Ruo-Fang Wang","message":"Change source directory for deployment"}]},"filePathRelative":"zh-tw/about.md"}`),u={name:`about.md`},d={class:`vp-hero-action-button primary`};function f(c,l,u,f,p,m){let h=t(`router-link`),g=t(`DynamicDuration`);return s(),o(`div`,null,[l[14]||=n(`<h1 id="關於我" tabindex="-1"><a class="header-anchor" href="#關於我"><span>關於我</span></a></h1><div class="about-me-container"><img src="/myWebPortfolios/images/my-photo.jpg" alt="Ruo-Fang&#39;s photo" class="photo"><div><h3>王若芳 Karen Wang</h3><h3>Front-end / UI / Web Developer</h3><h3>前端網頁開發者 / UI開發者</h3></div></div><h2 id="背景" tabindex="-1"><a class="header-anchor" href="#背景"><span>📋 背景</span></a></h2><p>我是一位專注的 <strong>前端工程師 (Front-end Engineer)</strong>，目前任職於 <strong>ViewSonic</strong>，專精於建構高效能桌面應用程式與網頁應用程式，並使用 <strong>React、TypeScript 與 Material-UI (MUI)</strong> 開發 <strong>內部 UI 元件庫</strong>。我的工作核心深植於創造具備無障礙性與包容性的數位體驗，包括實作符合 <strong>歐洲無障礙法案 (EAA)</strong> 的功能，並確保產品達到 <strong>WCAG 標準</strong>。</p><p>我畢業於 <strong>亞岡昆學院 (Algonquin College)</strong> 的互動媒體設計專業，以 <strong>3.95 的高 GPA</strong> 獲得院長榮譽 (Dean’s Honor)，這使我能有效銜接設計與技術執行之間的鴻溝。我的職涯經歷包括在 <strong>加拿大政府</strong> 擔任學生網頁發布員，期間透過自動化電子報模板提升了 33% 的工作效率；以及在 <strong>Agility PR Solutions</strong> 擔任 UI 開發實習生，專注於重構可複用元件並優化 SCSS 架構。</p><p>我的背景獨特且多元；在轉職成為工程師之前，我曾在 <strong>星展銀行 (DBS Bank) 擔任行銷專員</strong> 近三年，這段經歷磨練了我的溝通技巧與策略思考能力。結合在 <strong>國立臺北大學經濟系</strong> 取得的文學學士學位，讓我能以邏輯清晰、數據驅動的視角投入開發，並精確洞察業務影響力。我是一位終身學習者，曾投入 <strong>七個月的長假深造 React</strong> 核心技術；我熱衷於 <strong>Agile/Scrum</strong> 協作環境，致力於交付具備擴充性且高品質的網頁解決方案。</p>`,6),i(`div`,d,[a(h,{to:`/contact.html`,class:`action-button contact-me`,"aria-label":`Contact Me`},{default:r(()=>[...l[0]||=[e(`聯絡我`,-1)]]),_:1})]),l[15]||=n(`<h2 id="學歷" tabindex="-1"><a class="header-anchor" href="#學歷"><span>🎓 學歷</span></a></h2><ul><li><p><strong>Algonqion College</strong> - 渥太華, 安大略省, 加拿大</p><ul><li>互動媒體設計學憑 (Diploma, Interactive Media Design)</li><li>2021年9月 - 2023年8月</li><li>成績: GPA: 3.95</li><li>活動: 2021-2023 院長榮譽學生 (Dean Honor 2021-2023)</li><li>學習技能: <ul><li>網頁開發: HTML, CSS, SCSS, JavaScript, React, Vue, Vite, Git, GitHub</li><li>設計與媒體: Adobe Creative Suite</li><li>內容管理系統 (CMS): WordPress, Shopify</li><li>UI/UX: Adobe XD, Figma, Figjam</li></ul></li></ul></li><li><p><strong>國立台北大學</strong> - 新北市, 台灣</p><ul><li>經濟學學士</li><li>2013年9月 - 2017年6月</li><li>成績: GPA: 3.48</li><li>活動與社團: 2015-2016 古箏社社長</li></ul></li></ul><h2 id="技能" tabindex="-1"><a class="header-anchor" href="#技能"><span>💻 技能</span></a></h2><h3 id="網頁開發" tabindex="-1"><a class="header-anchor" href="#網頁開發"><span>網頁開發</span></a></h3><ul><li>React</li><li>React Redux</li><li>Redux Toolkit</li><li>JavaScript</li><li>Electron</li><li>Node.js</li><li>HTML</li><li>CSS</li><li>Sass/SCSS</li><li>Vue</li><li>Angular</li><li>TypeScript</li><li>Git &amp; GitHub</li><li>PHP</li><li>Liquid</li></ul><h3 id="uiux-設計" tabindex="-1"><a class="header-anchor" href="#uiux-設計"><span>UIUX 設計</span></a></h3><ul><li>Figma</li><li>Figjam</li><li>Adobe XD</li><li>Adobe Photoshop</li><li>Adobe Illustrator</li></ul><h3 id="內容管理系統-cms" tabindex="-1"><a class="header-anchor" href="#內容管理系統-cms"><span>內容管理系統 (CMS)</span></a></h3><ul><li>WordPress</li><li>Shopify</li><li>Adobe Experience Manager (AEM)</li></ul><h2 id="台灣工作經驗" tabindex="-1"><a class="header-anchor" href="#台灣工作經驗"><span>💼 台灣工作經驗 🇹🇼</span></a></h2><h3 id="前端工程師-front-end-engineer" tabindex="-1"><a class="header-anchor" href="#前端工程師-front-end-engineer"><span>前端工程師 (Front-end Engineer)</span></a></h3>`,11),i(`ul`,null,[l[2]||=i(`li`,null,`優派國際 · 全職正職 (Permanent)`,-1),i(`li`,null,[l[1]||=e(`2024年3月 - 現在 · `,-1),a(g,{from:`2024-03`,lang:`zh-tw`})]),l[3]||=n(`<li>新北市, 台灣 · 實體上班</li><li>工作內容: <ul><li>為桌面應用程式開發無障礙功能以符合 <strong>歐洲無障礙法案 (EAA)</strong>，並根據業務需求使用 <strong>Electron, React, React Router 與 TypeScript</strong> 實作新功能。</li><li>持續改進並<strong>重構 (Refactor)</strong> 現有程式碼以縮減套件體積並提升效能，致力於將應用程式當機風險降至最低。</li><li>建構供多個專案使用的<strong>內部私有 UI 元件庫</strong>，使用 <strong>React, TypeScript, 客製化 Material-UI (MUI)</strong> 及 <strong>Azure DevOps Artifacts</strong> 開發可複用元件。利用 <strong>Storybook</strong> 撰寫 UI 規範文件，並透過 <strong>Azure DevOps CI/CD</strong> 流水線將靜態文件佈署至 <strong>AWS S3</strong>。</li><li>根據 UI/UX 設計師提供的設計系統、樣板 (Mockups) 與原型 (Prototypes)，透過客製化 <strong>MUI 主題 (Themes)</strong>、元件與字體排版，確保高標準的 UI 品質與品牌一致性。</li><li>利用 <strong>React 生態系</strong>（包含 <strong>React Router, React Redux, Redux Toolkit 與 MUI</strong>）交付前端網頁解決方案。透過 <strong>Axios</strong> 整合 API 並使用 <strong>Lodash</strong> 處理資料交互；使用 <strong>Cypress</strong> 撰寫自動化測試，確保程式碼品質與功能可靠性。</li><li>在節奏快速的 <strong>Scrum</strong> 環境中表現出色，與 UI/UX 設計師、後端工程師、專案經理及產品開發經理緊密協作。在 <strong>Agile</strong> 衝刺週期中主動重新評估任務優先級，以優化整體開發效率。</li></ul></li>`,2)]),l[16]||=i(`h3`,{id:`行銷襄理-marketing-officer`,tabindex:`-1`},[i(`a`,{class:`header-anchor`,href:`#行銷襄理-marketing-officer`},[i(`span`,null,`行銷襄理 (Marketing Officer)`)])],-1),i(`ul`,null,[l[5]||=i(`li`,null,`星展銀行(台灣) · 全職正職 (Permanent)`,-1),i(`li`,null,[l[4]||=e(`2018年7月 - 2021年4月 · `,-1),a(g,{from:`2018-07`,to:`2021-04`,lang:`zh-tw`})]),l[6]||=i(`li`,null,`台北市, 台灣 · 實體上班`,-1),l[7]||=i(`li`,null,[e(`工作內容: `),i(`ul`,null,[i(`li`,null,`策劃了一系列從分行溝通到數位行銷的全面行銷策略，涵蓋多種消費銀行產品。在房貸的數位行銷活動中，保持令人印象深刻的NT$ 600 左右的 CPL，展現卓越的專業能力。`),i(`li`,null,`與多個小組的跨部門無縫合作，磨練並展現出色的領導和溝通技巧。`),i(`li`,null,`對包括貸款、存款和投資產品在內的消費銀行產品策略性地設計並執行社群媒體宣傳活動。`),i(`li`,null,`善用DBS Bank（新加坡）的資源，策劃並發布了21篇金融教育文章和影片。開創性地推出了每週兩次和每日的通訊，專門用於在尊貴的財富客戶中推廣投資產品，顯著提高了品牌在這一領域的知名度。`),i(`li`,null,`構思、組織和主持了針對基金的高度成功網路研討會，在令人印象深刻的一個月時間內實現了既定的產品目標。`)])],-1)]),l[17]||=i(`h2`,{id:`加拿大工作經驗`,tabindex:`-1`},[i(`a`,{class:`header-anchor`,href:`#加拿大工作經驗`},[i(`span`,null,`💼 加拿大工作經驗 🇨🇦`)])],-1),l[18]||=i(`h3`,{id:`網頁發布學生-student-web-publisher`,tabindex:`-1`},[i(`a`,{class:`header-anchor`,href:`#網頁發布學生-student-web-publisher`},[i(`span`,null,`網頁發布學生 (Student Web Publisher)`)])],-1),i(`ul`,null,[l[9]||=i(`li`,null,`加拿大政府 (兼職)`,-1),i(`li`,null,[l[8]||=e(`2022年6月 - 2023年8月 · `,-1),a(g,{from:`2022-06`,to:`2023-08`,lang:`zh-tw`})]),l[10]||=n(`<li>渥太華, 安大略省, 加拿大 · 實體和遠距混合上班</li><li>工作內容: <ul><li>進行了對網頁的全面品質保證檢查，確保符合WCAG標準，保持高度的可訪問性。</li><li>在回應客戶具體需求方面展現了在使用Adobe Experience Manager（AEM）有效實施設計的能力，製作定制的網頁，展現出熟練的技術。</li><li>成功修復了50個網頁中的壞連結，確保使用者能夠無縫導覽，並隨後以更新、功能正常的連結發布這些頁面。</li><li>透過AEM對221個過時頁面進行封存，優化整體用戶體驗。</li><li>在遷移後成功整合了772個新連結到網頁中，確保順暢過渡和最佳功能。</li><li>在創建和發布每週通訊時發揮了重要作用，使用HTML和CSS代碼在AEM文本區塊中增強了模板。這優化了編輯流程，節省了33%的工作時間，並使非代碼人員更容易進行維護。</li><li>使用Adobe Analytics生成深入的網頁分析報告，根據內部客戶的規格進行定制。報告包括重要的指標，如熱門搜索詞、訪問高峰時段等，為戰略決策提供有價值的見解。</li></ul></li><li>技能: <ul><li>Web Content Accessibility Guidelines (WCAG)</li><li>Adobe Experience Manager (AEM)</li><li>Adobe Analytics (AA)</li><li>HTML</li><li>CSS</li></ul></li>`,3)]),l[19]||=i(`h3`,{id:`ui開發工程師-實習-ui-developer-co-op`,tabindex:`-1`},[i(`a`,{class:`header-anchor`,href:`#ui開發工程師-實習-ui-developer-co-op`},[i(`span`,null,`UI開發工程師 (實習) (UI Developer Co-op)`)])],-1),i(`ul`,null,[l[12]||=i(`li`,null,`Agility PR Solutions · (全職實習)`,-1),i(`li`,null,[l[11]||=e(`2023年1月 - 2023年4月 · `,-1),a(g,{from:`2023-01`,to:`2023-04`,lang:`zh-tw`})]),l[13]||=n(`<li>渥太華, 安大略省, 加拿大 · 遠距上班</li><li>工作內容: <ul><li>應用HTML、SCSS、JavaScript 和基本的 Angular 技能，精通處理 UI 和 mock-ups 上的不一致之處。調整 SCSS 代碼細節以確保元件與設計模型完全一致，確保無縫的使用者體驗。</li><li>在多個產品頁面上更新了七個通用元件，包括勾選框、單選按鈕、輸入框、文本區域、選項、各種按鈕和側邊欄，利用 HTML、SCSS、JavaScript、Angular 和 Typescript，將它們更新與新的模型 (mock-ups) 一致。</li><li>透過有系統地根據新模型更新SCSS樣式表和變數，展現對設計過程中細節的高度關注。</li><li>熟練操作Jira框架，並在Agile/Scrum開發過程中解決100%指派的UI問題工單 (tickets)。在充滿活力的前端團隊中展現出色的時間管理和團隊協作技能，始終按時完成任務。</li></ul></li><li>技能: <ul><li>TypeScript</li><li>Angular</li><li>Front-End Development</li><li>Sass (SCSS)</li><li>Agile(Scrum) Development Process</li></ul></li>`,3)])])}var p=c(u,[[`render`,f]]);export{l as _pageData,p as default};